// Parse the eBay payout CSV. The webhook receives JSON {filename, data} where
// data is the base64-encoded CSV. (This avoids n8n's binary-property handling.)
const body = items[0].json.body || items[0].json;
if (!body.data) {
  throw new Error('Expected JSON body with a base64 `data` field. Got keys: ' + Object.keys(body).join(', '));
}
const text = Buffer.from(body.data, 'base64').toString('utf8');
const lines = text.split(/\r?\n/);
const headerIdx = lines.findIndex(l => l.startsWith('"Transaction creation date"'));
if (headerIdx === -1) throw new Error('Header row not found - upload an eBay payout CSV');

function parseRow(line) {
  const out = [];
  let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { inQ = !inQ; continue; }
    if (c === ',' && !inQ) { out.push(cur); cur = ''; continue; }
    cur += c;
  }
  out.push(cur);
  return out;
}

const header = parseRow(lines[headerIdx]);
const orderCol = header.indexOf('Order number');
const netCol = header.indexOf('Net amount');
const typeCol = header.indexOf('Type');
if (orderCol < 0 || netCol < 0) throw new Error('Required columns not found');

const groups = new Map();
for (let i = headerIdx + 1; i < lines.length; i++) {
  const row = parseRow(lines[i]);
  const order = (row[orderCol] || '').trim();
  const netRaw = (row[netCol] || '').replace(/,/g, '').trim();
  if (!order || order === '--') continue;
  if (!netRaw || netRaw === '--') continue;
  const net = Number(netRaw);
  if (!Number.isFinite(net)) continue;
  const g = groups.get(order) || { orderNumber: order, ebayNet: 0, rows: 0, types: new Set() };
  g.ebayNet += net;
  g.rows += 1;
  g.types.add((row[typeCol] || '').trim());
  groups.set(order, g);
}

return Array.from(groups.values()).map(g => ({
  json: { orderNumber: g.orderNumber, ebayNet: Math.round(g.ebayNet * 100) / 100, rows: g.rows, types: Array.from(g.types) }
}));

// Map each Find SO response (one Dolibarr order each, auto-unwrapped from
// Dolibarr's [] response) back to its eBay context via ref_client. Also emit
// MISSING entries for eBay orders Dolibarr didn't return.
const ebayMap = new Map();
for (const e of $('Parse and Group').all()) {
  ebayMap.set(e.json.orderNumber, e.json);
}

const seen = new Set();
const out = [];

for (const it of items) {
  const so = it.json;
  if (!so || !so.id || !so.ref_client) continue;
  const ebay = ebayMap.get(so.ref_client);
  if (!ebay) continue;
  seen.add(so.ref_client);
  out.push({ json: {
    orderNumber: ebay.orderNumber,
    ebayNet:     ebay.ebayNet,
    ebayRows:    ebay.rows,
    ebayTypes:   ebay.types,
    dolOrderId:  so.id,
    dolOrderRef: so.ref,
    status:      'pending',
  }});
}

for (const [orderNumber, ebay] of ebayMap) {
  if (seen.has(orderNumber)) continue;
  out.push({ json: {
    orderNumber: ebay.orderNumber,
    ebayNet:     ebay.ebayNet,
    ebayRows:    ebay.rows,
    ebayTypes:   ebay.types,
    dolOrderId:  null,
    dolOrderRef: null,
    dolNet:      0,
    diff:        ebay.ebayNet,
    invoices:    [],
    status:      'MISSING_IN_DOLIBARR',
  }});
}

return out;

// Each input item is a full Dolibarr order detail (linkedObjectsIds populated).
// Look up the eBay context by ref_client (NOT by index - HTTP nodes can drop items).
const classifyMap = new Map();
for (const c of $('Classify (found/missing)').all()) {
  if (c.json.status === 'pending') classifyMap.set(c.json.orderNumber, c.json);
}

const out = [];
for (const it of items) {
  const order = it.json;
  const ctx = classifyMap.get(order.ref_client);
  if (!ctx) continue;
  const linked = ((order.linkedObjectsIds || {}).facture) || {};
  const invoiceIds = Object.values(linked);
  const base = {
    orderNumber: ctx.orderNumber,
    ebayNet:     ctx.ebayNet,
    ebayRows:    ctx.ebayRows,
    ebayTypes:   ctx.ebayTypes,
    dolOrderId:  ctx.dolOrderId,
    dolOrderRef: ctx.dolOrderRef,
  };
  if (invoiceIds.length === 0) {
    out.push({ json: { ...base, hasInvoice: false, invoiceId: null } });
  } else {
    for (const invId of invoiceIds) {
      out.push({ json: { ...base, hasInvoice: true, invoiceId: invId } });
    }
  }
}
return out;

// Each input item is a Dolibarr invoice. Look up its parent order via the
// invoice's ref_client (which equals the eBay order number).
const classifyMap = new Map();
for (const c of $('Classify (found/missing)').all()) {
  if (c.json.status === 'pending') classifyMap.set(c.json.orderNumber, c.json);
}

const out = [];
for (const it of items) {
  const inv = it.json;
  if (!inv || !inv.id || !inv.ref_client) continue;
  const ctx = classifyMap.get(inv.ref_client);
  if (!ctx) continue;
  const isCredit = String(inv.type) === '2';
  let amt = Number(inv.total_ht || 0);
  if (isCredit && amt > 0) amt = -amt;
  out.push({ json: {
    orderNumber: ctx.orderNumber,
    ebayNet:     ctx.ebayNet,
    ebayRows:    ctx.ebayRows,
    ebayTypes:   ctx.ebayTypes,
    dolOrderId:  ctx.dolOrderId,
    dolOrderRef: ctx.dolOrderRef,
    invoice: { id: inv.id, ref: inv.ref, type: isCredit ? 'credit_note' : 'invoice', totalHt: amt },
  }});
}
return out;

// Combine the two streams coming into this node:
//   - per-invoice items (orders with at least one linked facture)
//   - 'no invoice' sentinel items (orders found in Dolibarr but with 0 linked factures)
// Group everything by orderNumber, sum invoice amounts, compute diff/status.
const byOrder = new Map();
for (const it of items) {
  const r = it.json;
  const key = r.orderNumber;
  if (!byOrder.has(key)) {
    byOrder.set(key, {
      orderNumber: r.orderNumber,
      ebayNet: r.ebayNet,
      ebayRows: r.ebayRows,
      ebayTypes: r.ebayTypes,
      dolOrderId: r.dolOrderId,
      dolOrderRef: r.dolOrderRef,
      dolNet: 0,
      invoices: [],
    });
  }
  if (r.invoice) {
    const agg = byOrder.get(key);
    agg.dolNet += r.invoice.totalHt;
    agg.invoices.push(r.invoice);
  }
}
const out = [];
for (const agg of byOrder.values()) {
  agg.dolNet = Math.round(agg.dolNet * 100) / 100;
  agg.diff = Math.round((agg.ebayNet - agg.dolNet) * 100) / 100;
  if (agg.invoices.length === 0) agg.status = 'NO_LINKED_INVOICES';
  else if (Math.abs(agg.diff) > 0.01) agg.status = 'MISMATCH';
  else agg.status = 'MATCH';
  out.push({ json: agg });
}
return out;

// Final summary + filtered lists.
// Defensively recover no-invoice rows from Expand to invoices. This keeps the
// report correct even if the IF false branch is missing or not wired in n8n.
const byOrder = new Map(items.map(i => [i.json.orderNumber, i.json]));
for (const it of $('Expand to invoices').all()) {
  const r = it.json;
  if (r.hasInvoice !== false || byOrder.has(r.orderNumber)) continue;
  byOrder.set(r.orderNumber, {
    orderNumber: r.orderNumber,
    ebayNet: r.ebayNet,
    ebayRows: r.ebayRows,
    ebayTypes: r.ebayTypes,
    dolOrderId: r.dolOrderId,
    dolOrderRef: r.dolOrderRef,
    dolNet: 0,
    diff: Math.round(r.ebayNet * 100) / 100,
    invoices: [],
    status: 'NO_LINKED_INVOICES',
  });
}
const all = Array.from(byOrder.values());
const matches  = all.filter(r => r.status === 'MATCH');
const mismatch = all.filter(r => r.status === 'MISMATCH');
const missing  = all.filter(r => r.status === 'MISSING_IN_DOLIBARR');
const noInv    = all.filter(r => r.status === 'NO_LINKED_INVOICES');
return [{
  json: {
    summary: {
      ordersCompared:    all.length,
      matches:           matches.length,
      mismatches:        mismatch.length,
      missingInDolibarr: missing.length,
      noLinkedInvoices:  noInv.length,
    },
    discrepancies: [...mismatch, ...missing, ...noInv],
    matches,
  }
}];
